tinymce.PluginManager.add('liveblog', function(editor, url) {
    //  editor.ui.registry.addIcon('stream', '<svg class="icon"><use xlink:href="../../svg/custom-icons.svg#stream"></use></svg>');
    // editor.ui.registry.addIcon('stream', '<svg width="24" height="24"><use xlink:href="../../tinymce/svg/custom-icons.svg#stream"></use></svg>');
    editor.ui.registry.addIcon('liveblog', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="18px" height="15px" viewBox="0 0 18 15" enable-background="new 0 0 18 15" xml:space="preserve">\n' +
        '<path fill-rule="evenodd" clip-rule="evenodd" d="M17,12h-2h-1v3l-4-3H7v-1h8V3h3v9H17z M3,13v-3H0V0h14v10H7L3,13z M4,4H2v2h2V4z\n' +
        '\t M10,6h2V4h-2V6z M8,4H6v2h2V4z"/>\n' +
        '</svg>');

    var ClickAction = function() {
        var liveBlogTagHtml = '{$smarty_live_blog}';
        var pattern = /\{\$smarty_live_blog\}/i
        var bodyContent = tinymce.activeEditor.getContent().toLowerCase();
        if(pattern.test(bodyContent)){

            var newBodyContent = bodyContent.replace(pattern.exec(bodyContent), '');
            tinyMCE.activeEditor.setContent('');
            tinymce.activeEditor.execCommand( 'mceInsertContent', 0, newBodyContent );
        } else {
            tinymce.activeEditor.execCommand( 'mceInsertContent', 0, liveBlogTagHtml );
        }
    };


    editor.ui.registry.addButton('liveblog', {
        tooltip: 'Liveblog',
        icon: 'liveblog',
        onAction: function () {
            // Open window
            ClickAction();
        }

    });

    editor.ui.registry.addMenuItem('liveblog', {
        text: 'Liveblog',
        icon: 'liveblog',
        onAction: function () {
            // Open window
            openDialog();
        }
    });

});